query:
SELECT id, entity, status, row_count, 
  DATE_FORMAT(started_at, '%H:%i:%s') as started,
  DATE_FORMAT(finished_at, '%H:%i:%s') as finished,
  TIMESTAMPDIFF(MINUTE, started_at, NOW()) as elapsed_min
FROM sync_logs WHERE section='boonphone' ORDER BY id DESC LIMIT 10;

SELECT COUNT(*) as payment_count FROM payment_transactions WHERE section='Boonphone';
SELECT COUNT(*) as contract_count FROM contracts WHERE section='Boonphone';
SELECT COUNT(*) as installment_count FROM installments WHERE section='Boonphone';

